consumer_query_patterns:
// All expect declarations without a corresponding iOS actual
MATCH (e:ExpectDeclaration)
WHERE NOT EXISTS { MATCH (a:ActualDeclaration {platform: 'ios'})-[:IMPLEMENTS]->(e) }
RETURN e.fqn, e.file_path

// ObjC export names that differ from Kotlin FQN (renamed via @ObjCName)
MATCH (o:ObjCExport {has_objc_name_annotation: true})
RETURN o.kotlin_fqn, o.objc_name, o.swift_name ORDER BY o.kotlin_fqn

// Bridge surface functions that are SKIE-enhanced (async/throws wrappers)
MATCH (o:ObjCExport {is_skie_enhanced: true})
RETURN o.kotlin_fqn, o.swift_name, o.export_kind

// Impact analysis: what iOS bridge symbols are affected when a shared class changes?
MATCH (e:ExpectDeclaration {fqn: $changed_fqn})<-[:IMPLEMENTS]-(a:ActualDeclaration)<-[:EXPOSES]-(o:ObjCExport)
RETURN o.swift_name, o.objc_name, o.export_kind
